import{_ as t,o as a,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Network Topologies","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/topologies.md","filePath":"theory/networks/topologies.md"}'),o={name:"theory/networks/topologies.md"};function i(l,e,r,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="network-topologies" tabindex="-1">Network Topologies <a class="header-anchor" href="#network-topologies" aria-label="Permalink to &quot;Network Topologies&quot;">​</a></h1><p>The arrangement of devices in a network — how they connect to each other physically and logically — is called the <strong>topology</strong>. The choice of topology affects cost, performance, reliability, and how easy it is to add or remove devices.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Network topologies are a Grade 11 topic. You need to know the diagram, advantages, and disadvantages of each topology for Paper 2.</p></div><hr><h2 id="what-is-a-topology" tabindex="-1">What is a Topology? <a class="header-anchor" href="#what-is-a-topology" aria-label="Permalink to &quot;What is a Topology?&quot;">​</a></h2><p><strong>Physical topology</strong> — the actual layout of cables and devices.<br><strong>Logical topology</strong> — how data flows through the network (may differ from physical).</p><p>The four main topologies you need to know:</p><table tabindex="0"><thead><tr><th>Topology</th><th>Shape</th><th>Key feature</th></tr></thead><tbody><tr><td><strong>Star</strong></td><td>Devices connect to central switch/hub</td><td>Most common; central failure = total failure</td></tr><tr><td><strong>Bus</strong></td><td>All devices on one shared cable</td><td>Simple; cable break = network fails</td></tr><tr><td><strong>Ring</strong></td><td>Devices in a circle; data travels one way</td><td>Each device regenerates signal; one break = network fails</td></tr><tr><td><strong>Mesh</strong></td><td>Every device connects to every other</td><td>Most reliable; very expensive</td></tr></tbody></table><hr><h2 id="star-topology" tabindex="-1">Star Topology <a class="header-anchor" href="#star-topology" aria-label="Permalink to &quot;Star Topology&quot;">​</a></h2><p>All devices connect to a <strong>central switch or hub</strong>. No direct connection between end devices.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    PC1       PC2</span></span>
<span class="line"><span>      \\       /</span></span>
<span class="line"><span>       SWITCH</span></span>
<span class="line"><span>      /   |   \\</span></span>
<span class="line"><span>   PC3   PC4   PC5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="advantages" tabindex="-1">Advantages <a class="header-anchor" href="#advantages" aria-label="Permalink to &quot;Advantages&quot;">​</a></h3><ul><li>If one cable fails, only that device is affected — rest of network continues</li><li>Easy to add or remove devices without disrupting network</li><li>Easier to detect faults and isolate problems</li><li>High performance — dedicated connection per device (with switch)</li><li>Most commonly used topology in modern LANs</li></ul><h3 id="disadvantages" tabindex="-1">Disadvantages <a class="header-anchor" href="#disadvantages" aria-label="Permalink to &quot;Disadvantages&quot;">​</a></h3><ul><li>Central switch/hub is a <strong>single point of failure</strong> — if it fails, entire network fails</li><li>Requires more cable than bus topology</li><li>Higher cost — central device must handle all connections</li></ul><hr><h2 id="bus-topology" tabindex="-1">Bus Topology <a class="header-anchor" href="#bus-topology" aria-label="Permalink to &quot;Bus Topology&quot;">​</a></h2><p>All devices connect to a single <strong>shared backbone cable</strong>. Data travels along the cable and all devices see every packet.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PC1 --- PC2 --- PC3 --- PC4 --- PC5</span></span>
<span class="line"><span>|_______________________________|</span></span>
<span class="line"><span>         Backbone cable</span></span>
<span class="line"><span>        (terminated at both ends)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>A <strong>terminator</strong> is placed at each end of the cable to prevent signal bounce.</p><h3 id="advantages-1" tabindex="-1">Advantages <a class="header-anchor" href="#advantages-1" aria-label="Permalink to &quot;Advantages&quot;">​</a></h3><ul><li>Simple and inexpensive to set up</li><li>Less cable used than star or mesh</li><li>Easy to extend (add devices to the cable)</li><li>Suitable for small networks</li></ul><h3 id="disadvantages-1" tabindex="-1">Disadvantages <a class="header-anchor" href="#disadvantages-1" aria-label="Permalink to &quot;Disadvantages&quot;">​</a></h3><ul><li>A break anywhere in the backbone cable = <strong>entire network fails</strong></li><li>All devices share bandwidth → performance degrades as more devices are added</li><li>Data collisions are common (all devices transmit on the same medium)</li><li>Difficult to isolate faults — entire cable must be checked</li><li>Not suitable for large networks</li></ul><hr><h2 id="ring-topology" tabindex="-1">Ring Topology <a class="header-anchor" href="#ring-topology" aria-label="Permalink to &quot;Ring Topology&quot;">​</a></h2><p>Devices are connected in a <strong>closed loop</strong> (ring). Data travels in one direction around the ring, passing through each device until it reaches its destination.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>     PC1</span></span>
<span class="line"><span>    /    \\</span></span>
<span class="line"><span>  PC4    PC2</span></span>
<span class="line"><span>    \\    /</span></span>
<span class="line"><span>     PC3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Each device acts as a <strong>repeater</strong>, boosting the signal as it passes through.</p><p><strong>Token Ring</strong> (older technology): a &quot;token&quot; passes around the ring; only the device holding the token can transmit.</p><h3 id="advantages-2" tabindex="-1">Advantages <a class="header-anchor" href="#advantages-2" aria-label="Permalink to &quot;Advantages&quot;">​</a></h3><ul><li>No data collisions (only one device transmits at a time)</li><li>Each device regenerates the signal — performs well over longer distances</li><li>Equal access for all devices</li></ul><h3 id="disadvantages-2" tabindex="-1">Disadvantages <a class="header-anchor" href="#disadvantages-2" aria-label="Permalink to &quot;Disadvantages&quot;">​</a></h3><ul><li>A single break in the ring = <strong>entire network fails</strong></li><li>Difficult to add or remove devices without disrupting the network</li><li>Slower than star topology in modern implementations</li><li>Largely replaced by star topology using Ethernet switches</li></ul><hr><h2 id="mesh-topology" tabindex="-1">Mesh Topology <a class="header-anchor" href="#mesh-topology" aria-label="Permalink to &quot;Mesh Topology&quot;">​</a></h2><p>Every device connects directly to every other device. Two types:</p><ul><li><strong>Full mesh</strong>: every device has a direct link to every other device</li><li><strong>Partial mesh</strong>: some devices have multiple connections, not all</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PC1 ——— PC2</span></span>
<span class="line"><span> |  \\  / |</span></span>
<span class="line"><span> |   \\/  |</span></span>
<span class="line"><span> |   /\\  |</span></span>
<span class="line"><span> |  /  \\ |</span></span>
<span class="line"><span>PC3 ——— PC4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Full mesh with 5 devices requires: n(n-1)/2 = 10 connections.</p><h3 id="advantages-3" tabindex="-1">Advantages <a class="header-anchor" href="#advantages-3" aria-label="Permalink to &quot;Advantages&quot;">​</a></h3><ul><li><strong>Highly redundant</strong> — multiple paths between devices; network continues if a link fails</li><li>No single point of failure</li><li>High performance — dedicated links between pairs of devices</li><li>Used in critical infrastructure (internet backbone, military networks)</li></ul><h3 id="advantages-summary" tabindex="-1">Advantages (summary) <a class="header-anchor" href="#advantages-summary" aria-label="Permalink to &quot;Advantages (summary)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Result</th></tr></thead><tbody><tr><td>Redundancy</td><td>If one link fails, data takes another path</td></tr><tr><td>No congestion</td><td>Dedicated links between pairs</td></tr><tr><td>Reliability</td><td>Most reliable of all topologies</td></tr></tbody></table><h3 id="disadvantages-3" tabindex="-1">Disadvantages <a class="header-anchor" href="#disadvantages-3" aria-label="Permalink to &quot;Disadvantages&quot;">​</a></h3><ul><li><strong>Very expensive</strong> — number of cables grows rapidly with more devices</li><li>Complex to install and manage</li><li>Impractical for large LANs</li></ul><hr><h2 id="topology-comparison" tabindex="-1">Topology Comparison <a class="header-anchor" href="#topology-comparison" aria-label="Permalink to &quot;Topology Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Star</th><th>Bus</th><th>Ring</th><th>Mesh</th></tr></thead><tbody><tr><td>Central device</td><td>Switch/Hub</td><td>None</td><td>None</td><td>None</td></tr><tr><td>Cable used</td><td>Moderate</td><td>Least</td><td>Moderate</td><td>Most</td></tr><tr><td>Cost</td><td>Moderate</td><td>Low</td><td>Moderate</td><td>Very high</td></tr><tr><td>Reliability</td><td>Medium (single point of failure)</td><td>Low</td><td>Low</td><td>Very high</td></tr><tr><td>Failure impact</td><td>One device loses connection</td><td>Whole network</td><td>Whole network</td><td>Minimal</td></tr><tr><td>Modern use</td><td>Very common</td><td>Rare</td><td>Rare</td><td>Internet backbone</td></tr><tr><td>Fault detection</td><td>Easy</td><td>Difficult</td><td>Difficult</td><td>Easy</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Topology</strong></td><td>The arrangement/layout of devices in a network</td></tr><tr><td><strong>Physical topology</strong></td><td>Actual physical layout of cables and devices</td></tr><tr><td><strong>Logical topology</strong></td><td>How data logically flows through the network</td></tr><tr><td><strong>Star topology</strong></td><td>All devices connect to a central switch</td></tr><tr><td><strong>Bus topology</strong></td><td>All devices on a single shared backbone cable</td></tr><tr><td><strong>Ring topology</strong></td><td>Devices form a closed loop; data travels in one direction</td></tr><tr><td><strong>Mesh topology</strong></td><td>Every device connects to every other device</td></tr><tr><td><strong>Terminator</strong></td><td>Device placed at ends of a bus cable to prevent signal bounce</td></tr><tr><td><strong>Single point of failure</strong></td><td>One component whose failure brings down the whole system</td></tr><tr><td><strong>Token</strong></td><td>Control signal passed around a ring; device holding it can transmit</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give TWO advantages of a star topology&quot;</strong> — failure of one cable only affects that device; easy to add/remove devices; easy fault detection</p></li><li><p><strong>&quot;Give TWO disadvantages of a star topology&quot;</strong> — central switch is a single point of failure; requires more cable than bus; higher cost</p></li><li><p><strong>&quot;Which topology is most reliable? Explain why.&quot;</strong> — Mesh; multiple paths exist between devices so if one link fails, data takes an alternative route</p></li><li><p><strong>&quot;What happens if the backbone cable in a bus topology breaks?&quot;</strong> — The entire network fails because all devices share the same cable</p></li><li><p><strong>&quot;Why is a ring topology rarely used in modern networks?&quot;</strong> — A single break fails the entire network; star topology with switches is faster and easier to manage</p></li></ol></div>`,56)])])}const u=t(o,[["render",i]]);export{g as __pageData,u as default};
